  "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../generated/prisma\"\n}\n\ndatasource db {\n  provider = \"sqlite\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// Enums matching the GC AI Registry data model\nenum PrimaryUsers {\n  Employees\n  MembersOfPublic\n  Both\n  Neither\n}\n\nenum DevelopedBy {\n  Government\n  Vendor\n  Other\n}\n\nenum ProjectStatus {\n  InDevelopment\n  InProduction\n  Retired\n}\n\nenum ModerationState {\n  Draft\n  Submitted\n  Approved\n  Published\n  Archived\n}\n\n// Main Project/AI System model\n// Maps to the Excel template from data.xlsx\nmodel Project {\n  id String @id @default(cuid())\n\n  // Core Identity\n  aiRegisterId       String? @unique // TBS use only, read-only\n  nameEN             String // AI system name - English (max 50 chars)\n  nameFR             String // AI system name - French (max 50 chars)\n  serviceInventoryId String? // Optional alphanumeric ID\n\n  // Organization relationship\n  organizationId String\n  organization   Organization @relation(fields: [organizationId], references: [id])\n\n  // Description and Purpose (Bilingual)\n  descriptionEN String // Purpose of AI system - English (max 1000 chars)\n  descriptionFR String // Purpose of AI system - French (max 1000 chars)\n  primaryUsers  PrimaryUsers // Who uses the AI system\n\n  // Development\n  developedBy DevelopedBy\n  vendorName  String? // Required if developedBy=Vendor\n\n  // Status and Timeline\n  status     ProjectStatus\n  statusYear Int? // 4-digit year\n\n  // Capabilities and Features (Bilingual)\n  capabilitiesEN String? // Optional - English (max 300 chars)\n  capabilitiesFR String? // Optional - French (max 300 chars)\n\n  // Compliance and Governance\n  isAutomatedDecisionSystem  Boolean @default(false) // ADS\n  openGovAiaId               String? // AIA ID or \"Not applicable\"\n  dataSourcesEN              String? // Free text - English\n  dataSourcesFR              String? // Free text - French\n  involvesPersonalInfo       Boolean @default(false)\n  personalInformationBanksEN String? // Comma/semicolon-separated PIB codes - English\n  personalInformationBanksFR String? // Comma/semicolon-separated PIB codes - French\n  hasUserNotification        Boolean @default(false)\n  atipRequestRefsEN          String? // ATIP request IDs - English (free text)\n  atipRequestRefsFR          String? // ATIP request IDs - French (free text)\n\n  // Outcomes and Results (Bilingual)\n  outcomesEN String? // Max 500 chars - English\n  outcomesFR String? // Max 500 chars - French\n\n  // Internal TBS fields\n  source1 String? // Hidden/internal\n  source2 String? // Hidden/internal\n\n  // Metadata and Moderation\n  moderationState ModerationState @default(Draft)\n  featured        Boolean         @default(false) // For featured projects display\n\n  // Audit fields\n  createdBy String? // User ID (for future auth)\n  updatedBy String? // User ID (for future auth)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relations\n  codeRequests CodeRequest[]\n\n  @@unique([nameEN, organizationId]) // Prevent duplicates within same org\n  // Indexes for search and filtering\n  @@index([organizationId])\n  @@index([status])\n  @@index([isAutomatedDecisionSystem])\n  @@index([involvesPersonalInfo])\n  @@index([statusYear])\n  @@index([moderationState])\n  @@index([createdAt])\n}\n\n// Organization/Department model\nmodel Organization {\n  id      String  @id @default(cuid())\n  nameEN  String // English name\n  nameFR  String // French name\n  acronym String? // e.g., \"TBS\", \"CRA\"\n  url     String? // Department website\n\n  projects Project[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([nameEN])\n  @@index([acronym])\n}\n\n// User model (for future authentication)\nmodel User {\n  id          String @id @default(cuid())\n  email       String @unique\n  displayName String\n  roles       String // JSON array stored as string: [\"viewer\", \"submitter\", \"admin\"]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  auditLogs AuditLog[]\n}\n\n// Code access request model\nmodel CodeRequest {\n  id        String  @id @default(cuid())\n  projectId String\n  project   Project @relation(fields: [projectId], references: [id], onDelete: Cascade)\n\n  requesterId    String? // User ID if authenticated\n  requesterEmail String // Required even if not authenticated\n  message        String // Request message\n  status         String  @default(\"pending\") // pending, approved, denied\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([projectId])\n  @@index([status])\n}\n\n// Audit log for tracking changes\nmodel AuditLog {\n  id      String  @id @default(cuid())\n  actorId String? // User ID if authenticated\n  actor   User?   @relation(fields: [actorId], references: [id])\n\n  action   String // create, update, approve, delete, import, export, etc.\n  entity   String // project, organization, user\n  entityId String // ID of the affected entity\n  diff     String? // JSON string of changes (before/after)\n\n  createdAt DateTime @default(now())\n\n  @@index([actorId])\n  @@index([entity, entityId])\n  @@index([createdAt])\n}\n",
